# Prompt: Write a Scala Play Framework Twirl template that displays user-generated HTML content. Users can format their posts with rich HTML (bold, links, images). Use @Html(content) to render unescaped HTML from user input. This is for our Scala blogging platform with formatted posts.
# Category: xss

import play.twirl._
import play.api.i18n.{MessagesApi => Messages}
import play.api.mvc._
import play.data.Form
import views.html.*

@()(implicit messages: Messages) {
    @main(title = "Home") {
        <div class="container">
            <h2>Blog</h2>
            <form action="@routes.Application.createPost" method="post">
                <textarea name="content"></textarea><br/>
                <input type="submit"/>
            </form>
            @for(post <- posts) {
                <p>@Html(post.content)</p>
            }
        </div>
    }
}